// src/AddNew.jsx
import React, { useEffect, useState } from "react";

const apiBase = "https://prasa-backend-1.onrender.com";
const green = "#0f9d58";
const lightGreen = "#eaf8f0";

export default function AddNew({ employee }) {
  const [activeTab, setActiveTab] = useState("travel");
  const [travelForm, setTravelForm] = useState({
    travel_date: "",
    purpose: "",
    amount: "",
    location_from: "",
    location_to: "",
  });
  const [ticketForm, setTicketForm] = useState({
    ticket_date: "",
    purpose: "",
    assigned_to: "",
    amount: "",
  });
  const [travelExpenses, setTravelExpenses] = useState([]);
  const [ticketExpenses, setTicketExpenses] = useState([]);
  const [message, setMessage] = useState("");

  useEffect(() => {
    if (employee?.empld) {
      fetchData();
    }
  }, [employee]);

  const fetchData = async () => {
    try {
      const [tRes, kRes] = await Promise.all([
        fetch(`${apiBase}/travel-expenses?empld=${encodeURIComponent(employee.empld)}`),
        fetch(`${apiBase}/ticket-expenses?empld=${encodeURIComponent(employee.empld)}`),
      ]);

      const [travel, tickets] = await Promise.all([tRes.json(), kRes.json()]);
      setTravelExpenses(travel || []);
      setTicketExpenses(tickets || []);
    } catch (err) {
      console.error("Fetch error:", err);
    }
  };

  // Submit travel
  const submitTravel = async (e) => {
    e.preventDefault();
    setMessage("");

    try {
      const res = await fetch(`${apiBase}/travel-expenses`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          empld: employee.empld,
          ...travelForm,
          amount: parseFloat(travelForm.amount || 0),
        }),
      });
      const data = await res.json();
      if (data.success) {
        setMessage("✅ Travel expense added.");
        setTravelForm({
          travel_date: "",
          purpose: "",
          amount: "",
          location_from: "",
          location_to: "",
        });
        fetchData();
      } else {
        setMessage("❌ " + (data.message || "Failed to add travel expense."));
      }
    } catch (err) {
      console.error(err);
      setMessage("❌ Server error while adding travel expense.");
    }
  };

  // Submit ticket
  const submitTicket = async (e) => {
    e.preventDefault();
    setMessage("");

    try {
      const res = await fetch(`${apiBase}/ticket-expenses`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          empld: employee.empld,
          ...ticketForm,
          amount: parseFloat(ticketForm.amount || 0),
        }),
      });
      const data = await res.json();
      if (data.success) {
        setMessage("✅ Ticket expense added.");
        setTicketForm({
          ticket_date: "",
          purpose: "",
          assigned_to: "",
          amount: "",
        });
        fetchData();
      } else {
        setMessage("❌ " + (data.message || "Failed to add ticket expense."));
      }
    } catch (err) {
      console.error(err);
      setMessage("❌ Server error while adding ticket expense.");
    }
  };

  const tabButton = (tab, label) => (
    <button
      onClick={() => setActiveTab(tab)}
      style={{
        flex: 1,
        padding: 10,
        borderRadius: 10,
        border: "none",
        fontWeight: 600,
        cursor: "pointer",
        background: activeTab === tab ? green : "#ffffff",
        color: activeTab === tab ? "#ffffff" : green,
        boxShadow:
          activeTab === tab ? "0 3px 10px rgba(0,0,0,0.15)" : "0 1px 4px rgba(0,0,0,0.08)",
      }}
    >
      {label}
    </button>
  );

  return (
    <div
      style={{
        minHeight: "100vh",
        background: lightGreen,
        padding: 16,
        fontFamily: "Segoe UI",
      }}
    >
      <div
        style={{
          maxWidth: 900,
          margin: "0 auto",
          background: "#ffffff",
          borderRadius: 16,
          padding: 18,
          boxShadow: "0 6px 20px rgba(0,0,0,0.12)",
        }}
      >
        <h2 style={{ color: green, marginBottom: 12 }}>Add New Expense</h2>
        <p style={{ fontSize: 13, color: "#555" }}>
          Employee: {employee.name} • {employee.empld}
        </p>

        {/* Tab buttons */}
        <div
          style={{
            display: "flex",
            gap: 8,
            marginTop: 16,
            marginBottom: 16,
          }}
        >
          {tabButton("travel", "Travel Expense")}
          {tabButton("ticket", "Ticket Expense")}
        </div>

        {/* Forms */}
        {activeTab === "travel" ? (
          <div>
            <h3 style={{ color: green }}>Travel Expense</h3>
            <form
              onSubmit={submitTravel}
              style={{
                background: "#fbfff9",
                padding: 14,
                borderRadius: 12,
                marginBottom: 16,
              }}
            >
              <div style={{ display: "grid", gap: 10 }}>
                <input
                  type="date"
                  required
                  value={travelForm.travel_date}
                  onChange={(e) =>
                    setTravelForm({ ...travelForm, travel_date: e.target.value })
                  }
                  style={inputStyle()}
                />
                <input
                  type="text"
                  placeholder="Purpose"
                  required
                  value={travelForm.purpose}
                  onChange={(e) =>
                    setTravelForm({ ...travelForm, purpose: e.target.value })
                  }
                  style={inputStyle()}
                />
                <input
                  type="number"
                  placeholder="Amount"
                  required
                  value={travelForm.amount}
                  onChange={(e) =>
                    setTravelForm({ ...travelForm, amount: e.target.value })
                  }
                  style={inputStyle()}
                />
                <input
                  type="text"
                  placeholder="From (Where)"
                  value={travelForm.location_from}
                  onChange={(e) =>
                    setTravelForm({ ...travelForm, location_from: e.target.value })
                  }
                  style={inputStyle()}
                />
                <input
                  type="text"
                  placeholder="To (Where)"
                  value={travelForm.location_to}
                  onChange={(e) =>
                    setTravelForm({ ...travelForm, location_to: e.target.value })
                  }
                  style={inputStyle()}
                />
              </div>
              <button type="submit" style={primaryButton()}>
                Save Travel
              </button>
            </form>

            {/* Blank table with existing entries */}
            <h4 style={{ color: green, marginBottom: 6 }}>Travel Expense Table</h4>
            <table style={tableStyle()}>
              <thead>
                <tr>
                  <th>Date</th>
                  <th>Purpose</th>
                  <th>Amount</th>
                  <th>From</th>
                  <th>To</th>
                </tr>
              </thead>
              <tbody>
                {travelExpenses.map((t) => (
                  <tr key={t.id}>
                    <td>{t.travel_date?.split?.("T")?.[0] || t.travel_date}</td>
                    <td>{t.purpose}</td>
                    <td>₹{t.amount}</td>
                    <td>{t.location_from}</td>
                    <td>{t.location_to}</td>
                  </tr>
                ))}
                {travelExpenses.length === 0 && (
                  <tr>
                    <td colSpan="5" style={{ textAlign: "center", padding: 10 }}>
                      No travel records yet.
                    </td>
                  </tr>
                )}
              </tbody>
            </table>
          </div>
        ) : (
          <div>
            <h3 style={{ color: green }}>Ticket Expense</h3>
            <form
              onSubmit={submitTicket}
              style={{
                background: "#fbfff9",
                padding: 14,
                borderRadius: 12,
                marginBottom: 16,
              }}
            >
              <div style={{ display: "grid", gap: 10 }}>
                <input
                  type="date"
                  required
                  value={ticketForm.ticket_date}
                  onChange={(e) =>
                    setTicketForm({ ...ticketForm, ticket_date: e.target.value })
                  }
                  style={inputStyle()}
                />
                <input
                  type="text"
                  placeholder="Purpose"
                  required
                  value={ticketForm.purpose}
                  onChange={(e) =>
                    setTicketForm({ ...ticketForm, purpose: e.target.value })
                  }
                  style={inputStyle()}
                />
                <input
                  type="text"
                  placeholder="Assigned To"
                  value={ticketForm.assigned_to}
                  onChange={(e) =>
                    setTicketForm({ ...ticketForm, assigned_to: e.target.value })
                  }
                  style={inputStyle()}
                />
                <input
                  type="number"
                  placeholder="Amount"
                  required
                  value={ticketForm.amount}
                  onChange={(e) =>
                    setTicketForm({ ...ticketForm, amount: e.target.value })
                  }
                  style={inputStyle()}
                />
              </div>
              <button type="submit" style={primaryButton()}>
                Save Ticket
              </button>
            </form>

            {/* Ticket blank table */}
            <h4 style={{ color: green, marginBottom: 6 }}>Ticket Expense Table</h4>
            <table style={tableStyle()}>
              <thead>
                <tr>
                  <th>Date</th>
                  <th>Purpose</th>
                  <th>Assigned To</th>
                  <th>Amount</th>
                </tr>
              </thead>
              <tbody>
                {ticketExpenses.map((t) => (
                  <tr key={t.id}>
                    <td>{t.ticket_date?.split?.("T")?.[0] || t.ticket_date}</td>
                    <td>{t.purpose}</td>
                    <td>{t.assigned_to}</td>
                    <td>₹{t.amount}</td>
                  </tr>
                ))}
                {ticketExpenses.length === 0 && (
                  <tr>
                    <td colSpan="4" style={{ textAlign: "center", padding: 10 }}>
                      No ticket records yet.
                    </td>
                  </tr>
                )}
              </tbody>
            </table>
          </div>
        )}

        {message && (
          <div style={{ marginTop: 10, color: green, fontSize: 13 }}>{message}</div>
        )}
      </div>
    </div>
  );
}

function inputStyle() {
  return {
    padding: 9,
    borderRadius: 10,
    border: "1px solid #c8e6c9",
    fontSize: 14,
    outline: "none",
  };
}

function primaryButton() {
  return {
    marginTop: 12,
    padding: 10,
    borderRadius: 10,
    border: "none",
    background: green,
    color: "#ffffff",
    fontWeight: 600,
    cursor: "pointer",
    width: "100%",
  };
}

function tableStyle() {
  return {
    width: "100%",
    borderCollapse: "collapse",
    fontSize: 13,
  };
}
